import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { map } from 'rxjs/operators';
import { Task, TaskStatus } from '../../core/models/crm.models';

@Component({
  selector: 'app-tasks-list',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './tasks-list.component.html',
  styleUrl: './tasks-list.component.css',
})
export class TasksListComponent {
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  private fb = inject(FormBuilder);

  // Backend-provided data. mockup_cleaner empties this; service_agent wires
  // it to TaskService.list() in ngOnInit().
  tasks = signal<Task[]>([
    { id: 't1', title: 'Send proposal to Globex', dueDate: '2026-07-13', status: 'Open', notes: 'Include Q3 pricing' },
    { id: 't2', title: 'Follow up with Initech CFO', dueDate: '2026-07-15', status: 'Open' },
    { id: 't3', title: 'Prep discovery call — Umbrella Co', dueDate: '2026-07-16', status: 'Open' },
    { id: 't4', title: 'Update CRM records after Q2 review', dueDate: '2026-07-05', status: 'Done' },
    { id: 't5', title: 'Draft renewal terms for Soylent', dueDate: '2026-07-20', status: 'Open', notes: 'Coordinate with legal' },
  ]);

  filter = signal<'all' | TaskStatus>('all');
  filtered = computed(() => {
    const f = this.filter();
    if (f === 'all') return this.tasks();
    return this.tasks().filter((t) => t.status === f);
  });
  openCount = computed(() => this.tasks().filter((t) => t.status === 'Open').length);

  private queryModal = toSignal(this.route.queryParamMap.pipe(map((p) => p.get('modal'))), {
    initialValue: this.route.snapshot.queryParamMap.get('modal'),
  });
  showCreate = computed(() => this.queryModal() === 'new');

  form = this.fb.group({
    title: ['', Validators.required],
    dueDate: [''],
    notes: [''],
  });

  setFilter(f: 'all' | TaskStatus): void {
    this.filter.set(f);
  }

  toggle(task: Task): void {
    this.tasks.update((list) =>
      list.map((t) => (t.id === task.id ? { ...t, status: t.status === 'Open' ? 'Done' : 'Open' } : t)),
    );
  }

  openCreate(): void {
    this.router.navigate([], { queryParams: { modal: 'new' }, queryParamsHandling: 'merge' });
  }
  closeCreate(): void {
    this.form.reset();
    this.router.navigate([], { queryParams: { modal: null }, queryParamsHandling: 'merge' });
  }

  submit(): void {
    if (this.form.invalid) return;
    const v = this.form.value;
    const task: Task = {
      id: 'tmp-' + this.tasks().length,
      title: v.title!,
      dueDate: v.dueDate || undefined,
      status: 'Open',
      notes: v.notes || undefined,
    };
    this.tasks.update((list) => [task, ...list]);
    this.closeCreate();
  }
}
